const body = $input.first().json.body || $input.first().json;
if (!body.client_id) throw new Error('Missing required field: client_id');
return [{ json: { client_id: body.client_id, pipeline_run_id: body.pipeline_run_id || null, started_at: new Date().toISOString() } }];

// Call the Python worker /cluster endpoint
const ctx = $('Validate_Cluster_Payload').first().json;
const client = ($('Fetch_Client').first().json || [])[0];
const classifications = $input.first().json || [];

if (!Array.isArray(classifications) || classifications.length === 0) {
  throw new Error('No passed keywords to cluster for client: ' + ctx.client_id);
}

// Build payload for worker: array of { id, embedding }
const items = classifications
  .filter(c => c.embedding)
  .map(c => ({ id: c.id, embedding: c.embedding }));

return [{
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    client_config: client?.config || {},
    classification_map: Object.fromEntries(classifications.map(c => [c.id, c])),
    worker_payload: { items }
  }
}];

// Parse worker response and prepare per-cluster LLM labeling requests
const ctx = $('Build_Cluster_Request').first().json;
const workerResp = $input.first().json;
const clusters = workerResp?.clusters || [];

if (!clusters.length) {
  throw new Error('Worker returned 0 clusters. Check /cluster endpoint and Supabase connectivity.');
}

return clusters.map(cluster => ({
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    client_config: ctx.client_config,
    cluster_id_from_worker: cluster.cluster_id,
    head_term: cluster.canonical_head_term || cluster.head_term || '',
    member_ids: cluster.member_ids || [],
    keyword_count: (cluster.member_ids || []).length,
    classification_map: ctx.classification_map
  }
}));

// Parse LLM cluster label and compute cannibalization check
const ctx = $('Parse_Worker_Response').item.json;
const llmRaw = $input.first().json;

let label = {};
try {
  label = JSON.parse(llmRaw.choices?.[0]?.message?.content || '{}');
} catch(e) {
  label = { theme_label: ctx.head_term, pillar_assignment_confidence: 0, niche_assignment_confidence: 0, content_theme: 'other' };
}

const needsTaxonomyReview = (label.pillar_assignment_confidence || 0) < 0.5 || (label.niche_assignment_confidence || 0) < 0.5;
const autoAssign = (label.pillar_assignment_confidence || 0) > 0.85;

return [{
  json: {
    ...ctx,
    label,
    needs_taxonomy_review: needsTaxonomyReview,
    auto_assign: autoAssign,
    llm_tokens: { input: llmRaw.usage?.prompt_tokens || 0, output: llmRaw.usage?.completion_tokens || 0 }
  }
}];
